    44→/// Read the frontmatter block (between `---` fences) of a markdown file and
    45→/// extract the `title`, `draft`, and `type` scalar values using simple line scanning.
    46→/// Returns `(None, None, None)` if the file can't be read or has no frontmatter.
    47→/// Uses a buffered reader so only the frontmatter is read, not the full file.
    48→fn read_frontmatter_meta(path: &Path) -> (Option<String>, Option<bool>, Option<String>) {
    49→    use std::io::{BufRead, BufReader};
    50→    let Ok(file) = std::fs::File::open(path) else {
    51→        return (None, None, None);
    52→    };
    53→    let mut reader = BufReader::new(file);
    54→    let mut first_line = String::new();
    55→    if reader.read_line(&mut first_line).is_err() || first_line.trim() != "---" {
    56→        return (None, None, None);
    57→    }
    58→    let mut title: Option<String> = None;
    59→    let mut draft: Option<bool> = None;
    60→    let mut content_type: Option<String> = None;
    61→    let mut line = String::new();
    62→    while reader.read_line(&mut line).unwrap_or(0) > 0 {
    63→        if line.trim() == "---" {
    64→            break;
    65→        }
    66→        if let Some(rest) = line.strip_prefix("title:") {
    67→            title = Some(rest.trim().trim_matches('"').trim_matches('\'').to_string());
    68→        } else if let Some(rest) = line.strip_prefix("draft:") {
    69→            let val = rest.trim();
    70→            draft = match val {
    71→                "true" => Some(true),
    72→                "false" => Some(false),
    73→                _ => None,
    74→            };
    75→        } else if let Some(rest) = line.strip_prefix("type:") {
    76→            let val = rest.trim().trim_matches('"').trim_matches('\'').to_string();
    77→            if !val.is_empty() {
    78→                content_type = Some(val);
    79→            }
    80→        }
    81→        line.clear();
    82→    }
    83→    (title, draft, content_type)
    84→}
