    96→fn walk_dir(path: &Path) -> Vec<FileNode> {
    97→    let Ok(entries) = std::fs::read_dir(path) else {
    98→        return Vec::new();
    99→    };
   100→
   101→    let mut entries: Vec<_> = entries.flatten().collect();
   102→    entries.sort_by_key(|e| e.file_name());
   103→
   104→    let mut nodes = Vec::new();
   105→
   106→    for entry in entries {
   107→        let entry_path = entry.path();
   108→        let name = entry.file_name().to_string_lossy().to_string();
   109→
   110→        if name.starts_with('.') {
   111→            continue;
   112→        }
   113→
   114→        if entry_path.is_dir() {
   115→            let children = walk_dir(&entry_path);
   116→            if !children.is_empty() {
   117→                nodes.push(FileNode {
   118→                    name,
   119→                    path: entry_path.to_string_lossy().to_string(),
   120→                    is_directory: true,
   121→                    children: Some(children),
   122→                    extension: None,
   123→                    title: None,
   124→                    draft: None,
   125→                    content_type: None,
   126→                });
   127→            }
   128→        } else {
   129→            let ext = entry_path
   130→                .extension()
   131→                .and_then(|e| e.to_str())
   132→                .unwrap_or("");
   133→            if ext == "md" || ext == "mdx" {
   134→                let (title, draft, content_type) = read_frontmatter_meta(&entry_path);
   135→                nodes.push(FileNode {
   136→                    name,
   137→                    path: entry_path.to_string_lossy().to_string(),
   138→                    is_directory: false,
   139→                    children: None,
   140→                    extension: Some(format!(".{}", ext)),
   141→                    title,
   142→                    draft,
   143→                    content_type,
   144→                });
   145→            }
   146→        }
   147→    }
   148→
   149→    nodes
   150→}
