   606→#[tauri::command]
   607→fn git_commit(
   608→    message: String,
   609→    push: bool,
   610→    state: State<'_, WorkspaceState>,
   611→) -> Result<(), String> {
   612→    let root_guard = state.tree_root.lock().map_err(|e| e.to_string())?;
   613→    let root = root_guard.as_ref().ok_or("no workspace open")?.clone();
   614→    drop(root_guard);
   615→    let root_str = root.to_string_lossy().to_string();
   616→    run_git(&root_str, &["add", "-A"])?;
   617→    run_git(&root_str, &["commit", "-m", &message])?;
   618→    if push {
   619→        run_git(&root_str, &["push"])?;
   620→    }
   621→    Ok(())
   622→}
   623→
   624→/// Compute a POSIX-style relative path from `from_dir` to `to`.
   625→fn relative_path_from(from_dir: &Path, to: &Path) -> String {
   626→    let from: Vec<_> = from_dir.components().collect();
   627→    let to_c: Vec<_> = to.components().collect();
   628→    let common = from.iter().zip(to_c.iter()).take_while(|(a, b)| a == b).count();
   629→    let mut rel = PathBuf::new();
   630→    for _ in common..from.len() {
   631→        rel.push("..");
   632→    }
   633→    for c in &to_c[common..] {
   634→        rel.push(c);
   635→    }
   636→    rel.to_string_lossy().replace('\\', "/")
   637→}
   638→
   639→/// Copy an image from an arbitrary path into `<workspace>/assets/` and return
   640→/// a path relative to the active markdown file (or `assets/<name>` as fallback).
   641→///
   642→/// Note: unlike `read_file`/`write_file`, `src_path` is intentionally not
   643→/// validated against the workspace root — drag-and-drop sources originate from
   644→/// external locations (desktop, downloads, etc.). The destination is safely
   645→/// constrained to `<workspace>/assets/`.
   646→#[tauri::command]
   647→fn save_asset(
   648→    src_path: String,
   649→    active_file_path: Option<String>,
   650→    state: State<'_, WorkspaceState>,
   651→) -> Result<String, String> {
   652→    let root_guard = state.tree_root.lock().map_err(|e| e.to_string())?;
   653→    let root = root_guard.as_ref().ok_or("no workspace open")?.clone();
   654→    drop(root_guard);
   655→
   656→    let src = Path::new(&src_path);
   657→    let file_name = src
   658→        .file_name()
   659→        .ok_or("invalid source path")?
   660→        .to_string_lossy()
   661→        .to_string();
   662→
   663→    let assets_dir = root.join("assets");
   664→    std::fs::create_dir_all(&assets_dir)
   665→        .map_err(|e| format!("could not create assets dir: {e}"))?;
   666→
   667→    // Atomically reserve a destination path to avoid TOCTOU races.
   668→    // Try the original name first; fall back to timestamp-prefixed candidates.
   669→    let dest_name = match std::fs::OpenOptions::new()
   670→        .write(true)
   671→        .create_new(true)
   672→        .open(assets_dir.join(&file_name))
   673→    {
   674→        Ok(_) => file_name.clone(),
   675→        Err(e) if e.kind() == std::io::ErrorKind::AlreadyExists => loop {
   676→            let ts = std::time::SystemTime::now()
   677→                .duration_since(std::time::UNIX_EPOCH)
   678→                .map(|d| d.as_millis())
   679→                .unwrap_or(0);
   680→            let candidate = format!("{ts}_{file_name}");
   681→            match std::fs::OpenOptions::new()
   682→                .write(true)
   683→                .create_new(true)
   684→                .open(assets_dir.join(&candidate))
   685→            {
   686→                Ok(_) => break candidate,
   687→                Err(e) if e.kind() == std::io::ErrorKind::AlreadyExists => continue,
   688→                Err(e) => return Err(format!("could not reserve asset path: {e}")),
   689→            }
   690→        },
   691→        Err(e) => return Err(format!("could not reserve asset path: {e}")),
   692→    };
   693→
   694→    let dest = assets_dir.join(&dest_name);
   695→    std::fs::copy(src, &dest).map_err(|e| format!("copy failed: {e}"))?;
   696→
   697→    // Return a path relative to the active file's directory when available.
   698→    let rel = if let Some(active) = active_file_path {
   699→        let from_dir = PathBuf::from(&active);
   700→        let from_dir = from_dir.parent().unwrap_or(Path::new(""));
   701→        relative_path_from(from_dir, &dest)
   702→    } else {
   703→        format!("assets/{dest_name}")
   704→    };
   705→
   706→    Ok(rel)
   707→}
