   203→#[tauri::command]
   204→async fn open_workspace_at_path(
   205→    path: String,
   206→    state: State<'_, WorkspaceState>,
   207→) -> Result<Option<WorkspaceResult>, String> {
   208→    let root = PathBuf::from(&path);
   209→    if !root.is_dir() {
   210→        return Ok(None);
   211→    }
   212→
   213→    let name = root
   214→        .file_name()
   215→        .map(|n| n.to_string_lossy().to_string())
   216→        .unwrap_or_else(|| root.to_string_lossy().to_string());
   217→
   218→    let content_dir = root.join("content");
   219→    let tree_root = if content_dir.is_dir() { content_dir } else { root.clone() };
   220→
   221→    *state.tree_root.lock().map_err(|e| e.to_string())? = Some(tree_root.clone());
   222→    *state.workspace_root.lock().map_err(|e| e.to_string())? = Some(root.clone());
   223→
   224→    let is_amytis_workspace = root.join("site.config.ts").is_file() && root.join("content").is_dir();
   225→    let tree = walk_dir(&tree_root);
   226→
   227→    Ok(Some(WorkspaceResult {
   228→        name,
   229→        root_path: root.to_string_lossy().to_string(),
   230→        tree_root: tree_root.to_string_lossy().to_string(),
   231→        tree,
   232→        is_amytis_workspace,
   233→    }))
   234→}
   235→
   236→#[tauri::command]
   237→async fn open_workspace(
   238→    app: tauri::AppHandle,
   239→    state: State<'_, WorkspaceState>,
   240→) -> Result<Option<WorkspaceResult>, String> {
   241→    let (tx, rx) = tokio::sync::oneshot::channel::<Option<tauri_plugin_dialog::FilePath>>();
   242→    app.dialog().file().pick_folder(move |folder| {
   243→        tx.send(folder).ok();
   244→    });
   245→    let folder = match rx.await.ok().flatten() {
   246→        Some(f) => f,
   247→        None => return Ok(None),
   248→    };
   249→    let root: PathBuf = match folder {
   250→        tauri_plugin_dialog::FilePath::Path(p) => p,
   251→        tauri_plugin_dialog::FilePath::Url(u) => PathBuf::from(u.path()),
   252→    };
   253→
   254→    let name = root
   255→        .file_name()
   256→        .map(|n| n.to_string_lossy().to_string())
   257→        .unwrap_or_else(|| root.to_string_lossy().to_string());
   258→
   259→    // Prefer content/ subdirectory for Amytis workspaces
   260→    let content_dir = root.join("content");
   261→    let tree_root = if content_dir.is_dir() {
   262→        content_dir
   263→    } else {
   264→        root.clone()
   265→    };
   266→
   267→    // Store roots for path validation and git/config commands
   268→    *state.tree_root.lock().map_err(|e| e.to_string())? = Some(tree_root.clone());
   269→    *state.workspace_root.lock().map_err(|e| e.to_string())? = Some(root.clone());
   270→
   271→    let is_amytis_workspace = root.join("site.config.ts").is_file() && root.join("content").is_dir();
   272→    let tree = walk_dir(&tree_root);
   273→
   274→    Ok(Some(WorkspaceResult {
   275→        name,
   276→        root_path: root.to_string_lossy().to_string(),
   277→        tree_root: tree_root.to_string_lossy().to_string(),
   278→        tree,
   279→        is_amytis_workspace,
   280→    }))
   281→}
