   290→#[tauri::command]
   291→fn read_file(path: String, state: State<'_, WorkspaceState>) -> Result<String, String> {
   292→    let root_guard = state.tree_root.lock().map_err(|e| e.to_string())?;
   293→    let root = root_guard.as_ref().ok_or("no workspace open")?;
   294→    let canonical = validate_path(root, &path)?;
   295→    std::fs::read_to_string(&canonical).map_err(|e| e.to_string())
   296→}
   297→
   298→#[tauri::command]
   299→fn write_file(path: String, content: String, state: State<'_, WorkspaceState>) -> Result<(), String> {
   300→    let root_guard = state.tree_root.lock().map_err(|e| e.to_string())?;
   301→    let root = root_guard.as_ref().ok_or("no workspace open")?;
   302→    let canonical = validate_path(root, &path)?;
   303→    write_atomic(&canonical, &content).map_err(|e| e.to_string())
   304→}
   305→
   306→#[tauri::command]
   307→fn create_file(path: String, content: String, state: State<'_, WorkspaceState>) -> Result<(), String> {
   308→    let root_guard = state.tree_root.lock().map_err(|e| e.to_string())?;
   309→    let root = root_guard.as_ref().ok_or("no workspace open")?;
   310→    let new_path = validate_new_path(root, &path)?;
   311→    if new_path.exists() {
   312→        return Err("file already exists".to_string());
   313→    }
   314→    write_atomic(&new_path, &content).map_err(|e| e.to_string())
   315→}
   316→
   317→#[tauri::command]
   318→fn rename_file(old_path: String, new_path: String, state: State<'_, WorkspaceState>) -> Result<(), String> {
   319→    let root_guard = state.tree_root.lock().map_err(|e| e.to_string())?;
